function candidate(from, to) {
  if (typeof from !== "string" || typeof to !== "string") {
    throw new TypeError("Path arguments must be strings");
  }
  if (from === to) {
    return "";
  }

  function normalizeAbsolute(input) {
    var base = "/";
    if (input.charAt(0) !== "/" && typeof process !== "undefined" && process && typeof process.cwd === "function") {
      base = process.cwd() || "/";
    }

    var combined = input.charAt(0) === "/" ? input : base + "/" + input;
    var pieces = combined.split("/");
    var stack = [];

    for (var i = 0; i < pieces.length; i++) {
      var part = pieces[i];
      if (!part || part === ".") {
        continue;
      }
      if (part === "..") {
        if (stack.length) {
          stack.pop();
        }
      } else {
        stack.push(part);
      }
    }

    return "/" + stack.join("/");
  }

  var start = normalizeAbsolute(from);
  var end = normalizeAbsolute(to);

  if (start === end) {
    return "";
  }

  var startParts = start === "/" ? [] : start.slice(1).split("/");
  var endParts = end === "/" ? [] : end.slice(1).split("/");
  var shared = 0;

  while (shared < startParts.length && shared < endParts.length && startParts[shared] === endParts[shared]) {
    shared++;
  }

  var result = [];
  for (var up = shared; up < startParts.length; up++) {
    result.push("..");
  }
  for (var down = shared; down < endParts.length; down++) {
    result.push(endParts[down]);
  }

  return result.join("/");
}
